 * Pulls a balanced string off the queue. E.g. if queue is "(one (two) three) four", (,) will return "one (two) three",
 * and leave " four" on the queue. Unbalanced openers and closers can quoted (with ' or ") or escaped (with \). Those escapes will be left
 * in the returned string, which is suitable for regexes (where we need to preserve the escape), but unsuitable for
 * contains text strings; use unescape for that.
 * @param open opener
 * @param close closer
 * @return data matched from the queue
 */
public String chompBalanced(char open, char close) {
    int start = -1;
    int end = -1;
    int depth = 0;
    char last = 0;
    boolean inQuote = false;
    boolean inCharMatch = false; // Track if we're currently processing after an ESC

    do {
        if (isEmpty()) break;
        Character c = consume();

        // Handle escape sequences
        if (last == ESC) {
            // Previous character was an escape, so current character is literal
            // Do not toggle quote state for escaped quotes
        } else {
            // Not escaped, so process normally
            if ((c.equals('\'') || c.equals('"')) && c != open) {
                inQuote = !inQuote;
            }
        }

        // Only process open/close brackets when not in quote mode
        if (!inQuote) {
            if (c.equals(open)) {
                depth++;
                if (start == -1)
                    start = pos;
            } else if (c.equals(close)) {
                depth--;
            }
        }

        if (depth > 0 && last != 0)
            end = pos; // don't include the outer match pair in the return
        last = c;
    } while (depth > 0);

    // If we exit because queue is empty but depth > 0, we couldn't find closing bracket
    // This indicates malformed input
    if (depth > 0) {
        // This suggests unbalanced brackets, likely due to unbalanced quotes
        throw new IllegalStateException("Unexpected end of queue whilst looking for balanced marker for '" + open + "' and '" + close + "'");
    }

    final String out = (end >= 0) ? queue.substring(start, end) : "";
    return out;
}

