 * in the returned string, which is suitable for regexes (where we need to preserve the escape), but unsuitable for
 * contains text strings; use unescape for that.
 * @param open opener
 * @param close closer
 * @return data matched from the queue
 */
public String chompBalanced(char open, char close) {
    int start = -1;
    int end = -1;
    int depth = 0;
    char last = 0;
    boolean inQuote = false;

    // Track if we detect a condition where we might have unbalanced quotes inside balanced content
    int initialPos = pos;

    do {
        if (isEmpty()) break;
        Character c = consume();
        if (last == 0 || last != ESC) {
            if ((c.equals('\'') || c.equals('"')) && c != open)
                inQuote = !inQuote;
            if (inQuote)
                continue;
            if (c.equals(open)) {
                depth++;
                if (start == -1)
                    start = pos;
            }
            else if (c.equals(close))
                depth--;
        }

        if (depth > 0 && last != 0)
            end = pos; // don't include the outer match pair in the return
        last = c;
    } while (depth > 0);

    // If we exit the loop with depth > 0, it means we couldn't find the closing bracket
    // This happens when quotes cause the algorithm to skip processing closing brackets
    // This indicates malformed input that should cause an error
    if (depth > 0) {
        // Reset position to try to provide a meaningful error
        pos = initialPos;
        throw new IllegalStateException("Could not find balanced marker for '" + open + "' and '" + close + "', potentially due to unbalanced quotes");
    }

    final String out = (end >= 0) ? queue.substring(start, end) : "";
    return out;
}

